import './style.css'
import { store } from './store.js'

export function initApp(root) {
  const counterBtn = root.querySelector('#counterBtn')
  const countSpan = root.querySelector('#count')

  function render(state) {
    if (state.loading) {
      if (countSpan) countSpan.textContent = '...'
      return
    }
    if (state.error) {
      if (countSpan) countSpan.textContent = 'Error'
      return
    }
    if (countSpan) countSpan.textContent = state.count
  }

  const unsub = store.subscribe(render)
  render(store.get())

  counterBtn?.addEventListener('click', () => {
    store.set({ count: store.get().count + 1 })
  })

  return unsub
}

if (typeof document !== 'undefined') {
  const root = document.getElementById('app')
  if (root) initApp(root)
}

import { describe, it, expect, beforeEach, afterEach } from 'vitest'
import { store } from './store.js'
import { initApp } from './main.js'

/**
 * Helper: build a minimal DOM root that mirrors the structure in index.html
 * without using innerHTML.
 */
function createRoot() {
  const root = document.createElement('div')
  root.id = 'app'

  const counterBtn = document.createElement('button')
  counterBtn.id = 'counterBtn'
  root.appendChild(counterBtn)

  const countSpan = document.createElement('span')
  countSpan.id = 'count'
  root.appendChild(countSpan)

  return root
}

describe('initApp()', () => {
  let root
  let unsub

  beforeEach(() => {
    store.reset()
    root = createRoot()
  })

  afterEach(() => {
    unsub?.()
  })

  it('renders the initial count value from the store into #count', () => {
    unsub = initApp(root)
    const countSpan = root.querySelector('#count')
    expect(countSpan.textContent).toBe('0')
  })

  it('increments the count when the counter button is clicked', () => {
    unsub = initApp(root)
    const counterBtn = root.querySelector('#counterBtn')
    const countSpan = root.querySelector('#count')

    counterBtn.click()
    expect(countSpan.textContent).toBe('1')

    counterBtn.click()
    expect(countSpan.textContent).toBe('2')
  })

  it('shows "..." in #count while the store is in loading state', () => {
    unsub = initApp(root)
    store.set({ loading: true })
    const countSpan = root.querySelector('#count')
    expect(countSpan.textContent).toBe('...')
  })

  it('shows "Error" in #count when the store has an error', () => {
    unsub = initApp(root)
    store.set({ loading: false, error: new Error('boom') })
    const countSpan = root.querySelector('#count')
    expect(countSpan.textContent).toBe('Error')
  })

  it('shows count after loading state clears', () => {
    unsub = initApp(root)
    const countSpan = root.querySelector('#count')
    store.set({ loading: true })
    expect(countSpan.textContent).toBe('...')
    store.set({ loading: false })
    expect(countSpan.textContent).toBe('0')
  })

  it('shows count after error state clears', () => {
    unsub = initApp(root)
    const countSpan = root.querySelector('#count')
    store.set({ error: new Error('boom') })
    expect(countSpan.textContent).toBe('Error')
    store.set({ error: null })
    expect(countSpan.textContent).toBe('0')
  })

  it('shows "..." if store is already in loading state when initApp is called', () => {
    store.set({ loading: true })
    unsub = initApp(root)
    expect(root.querySelector('#count').textContent).toBe('...')
  })

  it('shows "Error" if store already has an error when initApp is called', () => {
    store.set({ loading: false, error: new Error('pre-init error') })
    unsub = initApp(root)
    expect(root.querySelector('#count').textContent).toBe('Error')
  })

  it('does not throw when root has no #counterBtn', () => {
    const bareRoot = document.createElement('div')
    const countSpan = document.createElement('span')
    countSpan.id = 'count'
    bareRoot.appendChild(countSpan)
    expect(() => { unsub = initApp(bareRoot) }).not.toThrow()
  })

  it('does not throw when root has no #count span', () => {
    const bareRoot = document.createElement('div')
    const btn = document.createElement('button')
    btn.id = 'counterBtn'
    bareRoot.appendChild(btn)
    expect(() => { unsub = initApp(bareRoot) }).not.toThrow()
  })

  it('unsub stops DOM updates after being called', () => {
    unsub = initApp(root)
    const countSpan = root.querySelector('#count')
    unsub()
    store.set({ count: 99 })
    expect(countSpan.textContent).toBe('0')
  })

  it('silently increments count in store while loading — display stays at "..."', () => {
    unsub = initApp(root)
    const countSpan = root.querySelector('#count')
    const counterBtn = root.querySelector('#counterBtn')

    store.set({ loading: true })
    expect(countSpan.textContent).toBe('...')

    counterBtn.click()
    expect(countSpan.textContent).toBe('...')  // UI unchanged
    expect(store.get().count).toBe(1)           // store updated
  })
})

